                    reply_markup=origin_link(f.url),
                    thumbnail=mediathumb,
                    title=f.mediatitle,
                    write_timeout=600,
                )
            elif len(f.mediaurls) == 1:
                if ".gif" in f.mediaurls[0]:
                    await message.reply_animation(
                        media[0],
