        )
        if not success:
            raise HTTPException(status_code=404, detail="Mission or drone not found")
        return {"success": True}

    @router.post("/poi", response_model=POI)
    async def create_poi(poi: POI, mission_id: str = Query(..., description="Mission ID")):
