def test_export_failure(self, capsys):
    """Test handling of export failure."""
    mock_result = mock_result = {
        "success": False,
        "metadata": {
            "successful_jobs": 0,
            "failed_jobs": 1,
            "skipped_jobs": 0,
        },
    }
    with patch(
        "nemo_evaluator_launcher.api.functional.export_results",
        return_value=mock_result,
