def reaggregate_all_finding_group_summaries_task(tenant_id: str):
    """Reaggregate finding group summaries for all providers' latest completed scans."""
    latest_scan_ids = list(
        Scan.objects.filter(tenant_id=tenant_id, state=StateChoices.COMPLETED)
        .order_by("provider_id", "-completed_at", "-inserted_at")
        .distinct("provider_id")
        .values_list("id", flat=True)
    )
    if latest_scan_ids:
        logger.info(
            "Reaggregating finding group summaries for %d scans: %s",
            len(latest_scan_ids),
            latest_scan_ids,
        )
        group(
            aggregate_finding_group_summaries_task.si(
                tenant_id=tenant_id, scan_id=str(scan_id)
            )
            for scan_id in latest_scan_ids
        ).apply_async()
    return {"scans_reaggregated": len(latest_scan_ids)}

def get_seeds(self, sort=False, resolve_redirects=False) -> list['Seed']:
    # Need to query for a series' seeds
    work_keys = web.ctx.site.things(
        {
            'type': '/type/work',
            'series': {'series': {'key': self.key}},
        }
    )
    works = cast(list[Work], web.ctx.site.get_many(work_keys))
    series_edges = [
        (work, edge) for work in works if (edge := work.find_series_edge(self.key))
    ]

    def get_work_position(position: str | None) -> float:
        position_float = 9999.0
        with contextlib.suppress(ValueError):
            position_float = float(position or 9999)
        return position_float

    sorted_edges = sorted(
        series_edges, key=lambda tpl: get_work_position(tpl[1].get('position'))
    )

    seeds: list[Seed] = []
    for work, edge in sorted_edges:
        seed_json = cast(AnnotatedSeedDict, {'thing': {'key': work.key}})
        update_list_seed_metadata(seed_json, edge)
        seeds.append(Seed.from_json(self, seed_json))
    return seeds

